<script setup lang="ts">
import{computed}from'vue';import{useMutation,useQuery,useQueryClient}from'@tanstack/vue-query';import{Boxes,Database,RefreshCw,Server,ShieldCheck}from'lucide-vue-next';import Button from'@/components/ui/Button.vue';import StatusBadge from'@/components/ui/StatusBadge.vue';import{getHosts,getJobs,getProxmoxSummary,syncProxmox}from'@/lib/api';const client=useQueryClient();const summary=useQuery({queryKey:['proxmox-summary'],queryFn:getProxmoxSummary,refetchInterval:15000});const hosts=useQuery({queryKey:['hosts'],queryFn:getHosts});const jobs=useQuery({queryKey:['jobs'],queryFn:getJobs,refetchInterval:3000});const sync=useMutation({mutationFn:syncProxmox,onSuccess:()=>{client.invalidateQueries({queryKey:['jobs']});setTimeout(()=>{client.invalidateQueries({queryKey:['proxmox-summary']});client.invalidateQueries({queryKey:['hosts']})},2500)}});const nodes=computed(()=>hosts.data.value?.filter(h=>h.name.startsWith('proxmox:'))??[]);const lastJob=computed(()=>jobs.data.value?.find(j=>j.kind==='proxmox.sync'))
</script>
<template><div class="mx-auto max-w-[1680px] space-y-5"><header class="flex flex-col justify-between gap-4 md:flex-row md:items-end"><div><div class="flex gap-2"><StatusBadge :status="summary.data.value?.configured?'healthy':'warning'" :label="summary.data.value?.configured?'adapter configured':'configuration required'"/><span class="inline-flex items-center gap-1.5 font-mono text-[10px] uppercase tracking-wider text-signal"><ShieldCheck class="h-3.5 w-3.5"/>read-only token</span></div><h1 class="mt-4 text-3xl font-semibold tracking-tight">Proxmox fabric</h1><p class="mt-2 text-sm text-muted">Inventário normalizado diretamente da API PVE, sem scraping da interface.</p></div><Button :disabled="!summary.data.value?.configured||sync.isPending.value" @click="sync.mutate()"><RefreshCw :class="['h-4 w-4',sync.isPending.value&&'animate-spin']"/>Sincronizar inventário</Button></header><section class="grid gap-3 sm:grid-cols-2 xl:grid-cols-4"><article v-for="item in [{label:'Nodes',value:summary.data.value?.nodes??0,icon:Server},{label:'Virtual machines',value:summary.data.value?.virtual_machines??0,icon:Boxes},{label:'LXC containers',value:summary.data.value?.containers??0,icon:Database},{label:'Provider state',value:summary.data.value?.status??'unknown',icon:ShieldCheck}]" :key="item.label" class="rounded-xl border border-line bg-panel/65 p-5"><component :is="item.icon" class="h-4 w-4 text-muted"/><p class="mt-5 font-mono text-2xl text-white">{{item.value}}</p><p class="mt-1 text-xs text-muted">{{item.label}}</p></article></section><section class="grid gap-5 xl:grid-cols-[1fr_340px]"><article class="overflow-hidden rounded-xl border border-line bg-panel/65"><header class="border-b border-line px-5 py-4"><h2 class="text-sm font-medium">Cluster nodes</h2><p class="mt-1 text-xs text-muted">Status persistido no último sync concluído</p></header><div class="divide-y divide-line/60"><div v-for="node in nodes" :key="node.id" class="grid grid-cols-[1fr_120px_120px] items-center px-5 py-4"><div><p class="text-sm text-slate-200">{{node.name.replace('proxmox:','')}}</p><p class="font-mono text-[10px] text-muted">{{node.hostname}}</p></div><span class="font-mono text-[10px] uppercase text-muted">{{node.scope}}</span><StatusBadge :status="node.status==='online'?'healthy':'critical'" :label="node.status"/></div><p v-if="!nodes.length" class="p-10 text-center text-sm text-muted">Execute o primeiro sync depois de configurar as variáveis Proxmox.</p></div></article><aside class="rounded-xl border border-line bg-panel/50 p-5"><p class="font-mono text-[9px] uppercase tracking-widest text-muted">Last sync job</p><div v-if="lastJob" class="mt-4"><StatusBadge :status="lastJob.status==='succeeded'?'healthy':lastJob.status==='failed'?'critical':'info'" :label="lastJob.status"/><p class="mt-4 font-mono text-[10px] text-muted">{{lastJob.id}}</p><p class="mt-2 text-xs text-slate-300">Tentativa {{lastJob.attempts}} / {{lastJob.max_attempts}}</p><p v-if="lastJob.last_error" class="mt-3 break-words text-xs leading-5 text-danger">{{lastJob.last_error}}</p></div><p v-else class="mt-4 text-xs text-muted">Nenhum sync enfileirado.</p></aside></section></div></template>

